5	
6	import React, { useState } from 'react';
7	import { motion, AnimatePresence } from 'motion/react';
8	import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
9	import { db } from './firebase';
10	import { getJobsForPostcode, type Job, type RegionData } from './data/jobs';
11	
12	type AnalyticsEventName =
13	  | 'hero_cta_click'
14	  | 'filter_scan_start'
15	  | 'filter_scan_complete'
16	  | 'pricing_plan_click'
17	  | 'upgrade_cta_click'
18	  | 'nav_cta_click'
19	  | 'tool_used';
20	
21	declare global {
22	  interface Window {
23	    dataLayer?: Array<Record<string, unknown>>;
24	  }
25	}
26	
27	// ─── Tool Types ───────────────────────────────────────────────────────────────
28	type ToolId =
29	  | 'quote'
30	  | 'dayrate'
31	  | 'leadvalue'
32	  | 'markup'
33	  | 'timeestimate'
34	  | 'fuelcost'
35	  | 'invoice'
36	  | 'profit'
37	  | 'cashflow'
38	  | 'vatcheck';
39	
40	export default function App() {
41	  // ── Filter state ────────────────────────────────────────────────────────────
42	  const [quotesPerWeek, setQuotesPerWeek] = useState(5);
43	  const [milesDriven, setMilesDriven] = useState(20);
44	  const [postcode, setPostcode] = useState('');
45	  const [tradeType, setTradeType] = useState('general');
46	  const [showModal, setShowModal] = useState<string | null>(null);
47	  const [isScanning, setIsScanning] = useState(false);
48	  const [scanComplete, setScanComplete] = useState(false);
49	  const [scanJobs, setScanJobs] = useState<Job[]>([]);
50	  const [scanRegion, setScanRegion] = useState<RegionData | null>(null);
51	  const [scanFiltered, setScanFiltered] = useState(0);
52	  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
53	  const [waitlistPlan, setWaitlistPlan] = useState('');
54	  const [waitlistEmail, setWaitlistEmail] = useState('');
55	  const [waitlistSubmitted, setWaitlistSubmitted] = useState(false);
56	  const [activeToolId, setActiveToolId] = useState<ToolId | null>(null);
57	
58	  // ── Tool: Quote Quick Builder ────────────────────────────────────────────────
59	  const [qtLabour, setQtLabour] = useState(6);
60	  const [qtRate, setQtRate] = useState(35);
61	  const [qtMaterials, setQtMaterials] = useState(120);
62	  const [qtMarkup, setQtMarkup] = useState(20);
63	  const qtMaterialsTotal = qtMaterials * (1 + qtMarkup / 100);
64	  const qtLabourTotal = qtLabour * qtRate;
65	  const qtTotal = qtLabourTotal + qtMaterialsTotal;
66	
67	  // ── Tool: Day Rate Calculator ────────────────────────────────────────────────
68	  const [drAnnualTarget, setDrAnnualTarget] = useState(40000);
69	  const [drDaysWorked, setDrDaysWorked] = useState(220);
70	  const [drOverheads, setDrOverheads] = useState(5000);
71	  const drRequired = Math.ceil((drAnnualTarget + drOverheads) / drDaysWorked);
72	
73	  // ── Tool: Lead Value Checker ─────────────────────────────────────────────────
74	  const [lvBudget, setLvBudget] = useState('');
75	  const [lvScope, setLvScope] = useState('small');
76	  const [lvDistance, setLvDistance] = useState(10);
77	  const [lvPayType, setLvPayType] = useState('card');
78	  const getLvScore = () => {
79	    let score = 50;
80	    const b = parseFloat(lvBudget) || 0;
81	    if (b >= 2000) score += 25; else if (b >= 500) score += 15; else if (b >= 200) score += 5;
82	    if (lvScope === 'large') score += 15; else if (lvScope === 'medium') score += 8;
83	    if (lvDistance <= 5) score += 10; else if (lvDistance <= 15) score += 5; else score -= 10;
84	    if (lvPayType === 'card' || lvPayType === 'bank') score += 5;
85	    return Math.min(99, Math.max(20, score));
86	  };
87	  const lvScore = getLvScore();
88	  const lvLabel = lvScore >= 75 ? 'High Value' : lvScore >= 55 ? 'Worth Quoting' : 'Low Value — Skip';
89	  const lvColor = lvScore >= 75 ? 'text-green-400' : lvScore >= 55 ? 'text-amber-400' : 'text-red-400';
90	
91	  // ── Tool: Material Markup Calculator ────────────────────────────────────────
92	  const [mmCost, setMmCost] = useState(200);
93	  const [mmMarkup, setMmMarkup] = useState(25);
94	  const mmCharge = mmCost * (1 + mmMarkup / 100);
95	  const mmProfit = mmCharge - mmCost;
96	
97	  // ── Tool: Time Estimate Tool ─────────────────────────────────────────────────
98	  const [teScope, setTeScope] = useState('medium');
99	  const [teTrade, setTeTrade] = useState('general');
100	  const [teAccess, setTeAccess] = useState('easy');
101	  const getTeHours = () => {
102	    const base: Record<string, number> = { small: 2, medium: 6, large: 16, major: 40 };
103	    const tradeMulti: Record<string, number> = { general: 1, electrical: 1.2, plumbing: 1.1, heating: 1.3, building: 0.9 };
104	    const accessMulti: Record<string, number> = { easy: 1, moderate: 1.2, difficult: 1.5 };
105	    return Math.round((base[teScope] || 6) * (tradeMulti[teTrade] || 1) * (accessMulti[teAccess] || 1));
106	  };
107	  const teHours = getTeHours();
108	
109	  // ── Tool: Fuel Cost Calculator ───────────────────────────────────────────────
110	  const [fcMiles, setFcMiles] = useState(20);
111	  const [fcMpg, setFcMpg] = useState(35);
112	  const [fcPrice, setFcPrice] = useState(148);
113	  const [fcTrips, setFcTrips] = useState(1);
114	  const fcLitresPerTrip = (fcMiles / fcMpg) * 4.546;
115	  const fcCostPerTrip = (fcLitresPerTrip * fcPrice) / 100;
116	  const fcTotal = fcCostPerTrip * fcTrips;
117	
118	  // ── Tool: Invoice Generator ──────────────────────────────────────────────────
119	  const [invClient, setInvClient] = useState('');
120	  const [invJob, setInvJob] = useState('');
121	  const [invLabour, setInvLabour] = useState(0);
122	  const [invMaterials, setInvMaterials] = useState(0);
123	  const [invVat, setInvVat] = useState(false);
124	  const invSubtotal = invLabour + invMaterials;
125	  const invVatAmt = invVat ? invSubtotal * 0.2 : 0;
126	  const invTotal = invSubtotal + invVatAmt;
127	  const [invGenerated, setInvGenerated] = useState(false);
128	  const invDate = new Date().toLocaleDateString('en-GB');
129	  const invNumber = `JF-${Date.now().toString().slice(-5)}`;
130	
131	  // ── Tool: Profit Margin Calculator ──────────────────────────────────────────
132	  const [pmRevenue, setPmRevenue] = useState(500);
133	  const [pmCosts, setPmCosts] = useState(300);
134	  const pmProfit = pmRevenue - pmCosts;
135	  const pmMargin = pmRevenue > 0 ? ((pmProfit / pmRevenue) * 100).toFixed(1) : '0';
136	  const pmLabel = parseFloat(pmMargin) >= 40 ? 'Healthy' : parseFloat(pmMargin) >= 20 ? 'Tight' : 'Too Low';
137	  const pmColor = parseFloat(pmMargin) >= 40 ? 'text-green-400' : parseFloat(pmMargin) >= 20 ? 'text-amber-400' : 'text-red-400';
138	
139	  // ── Tool: Cash Flow Forecaster ───────────────────────────────────────────────
140	  const [cfWeeklyIn, setCfWeeklyIn] = useState(1200);
141	  const [cfWeeklyOut, setCfWeeklyOut] = useState(800);
142	  const cfWeeklyNet = cfWeeklyIn - cfWeeklyOut;
143	  const cfMonthlyNet = cfWeeklyNet * 4.33;
144	  const cfAnnualNet = cfWeeklyNet * 52;
145	
146	  // ── Tool: VAT Threshold Checker ──────────────────────────────────────────────
147	  const [vtTurnover, setVtTurnover] = useState(60000);
148	  const vtThreshold = 90000;
149	  const vtGap = vtThreshold - vtTurnover;
150	  const vtOver = vtTurnover > vtThreshold;
151	  const vtPercent = Math.min(100, (vtTurnover / vtThreshold) * 100);
152	
153	  // ── ROI ─────────────────────────────────────────────────────────────────────
154	  const hourlyRate = 45;
155	  const timePerQuote = 1.5;
156	  const fuelCostPerMile = 0.20;
157	  const annualAdminDebt = Math.round((quotesPerWeek * timePerQuote * hourlyRate + milesDriven * fuelCostPerMile) * 52);
158	  const jobFilterSavings = Math.round(annualAdminDebt * 0.85);
159	
160	  // ── Lead quality (based on actual scan results) ───────────────────────────
161	  const todayJobs = scanJobs.filter(j => j.urgency === 'TODAY').length;
162	  const highValueJobs = scanJobs.filter(j => j.value >= 1000).length;
163	  const leadQualityScore = scanComplete && scanJobs.length > 0
164	    ? Math.min(94, 55 + todayJobs * 8 + highValueJobs * 5)
165	    : 0;
166	
167	  const trackEvent = (eventName: AnalyticsEventName, params: Record<string, unknown> = {}) => {
168	    const eventPayload = { event: eventName, ...params, timestamp: new Date().toISOString() };
169	    if (typeof window !== 'undefined') { window.dataLayer = window.dataLayer || []; window.dataLayer.push(eventPayload); }
170	  };
171	
172	  const openWaitlist = (plan: string) => { setWaitlistPlan(plan); setWaitlistEmail(''); setWaitlistSubmitted(false); setShowModal('waitlist'); };
173	
174	  const submitWaitlist = async (e: React.FormEvent) => {
175	    e.preventDefault();
176	    if (!waitlistEmail.trim()) return;
177	    trackEvent('pricing_plan_click', { plan: waitlistPlan, source: 'waitlist_submit' });
178	    const email = waitlistEmail.trim().toLowerCase();
179	    await Promise.allSettled([
180	      addDoc(collection(db, 'waitlist'), { email, plan: waitlistPlan, createdAt: serverTimestamp() }),
181	      fetch('/api/waitlist', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ email, plan: waitlistPlan }) }),
182	    ]);
183	    setWaitlistSubmitted(true);
184	  };
185	
186	  const startScan = () => {
187	    setIsScanning(true); setScanComplete(false); setScanJobs([]); setScanRegion(null);
188	    trackEvent('filter_scan_start', { postcode_present: postcode.trim().length >= 4 });
189	    setTimeout(() => {
190	      const { jobs, regionData, filtered } = getJobsForPostcode(postcode, tradeType);
191	      setScanJobs(jobs);
192	      setScanRegion(regionData);
193	      setScanFiltered(filtered);
194	      setIsScanning(false);
195	      setScanComplete(true);
196	      trackEvent('filter_scan_complete', { region: regionData?.city ?? 'unknown', jobs_found: jobs.length });
197	    }, 1800);
198	  };
199	
200	  const tools = [
201	    { id: 'quote' as ToolId, icon: '📋', label: 'Quote Builder', desc: 'Build a quote in 30 seconds' },
202	    { id: 'dayrate' as ToolId, icon: '💷', label: 'Day Rate Calc', desc: 'Find your minimum day rate' },
203	    { id: 'leadvalue' as ToolId, icon: '🎯', label: 'Lead Value Checker', desc: 'Is this job worth chasing?' },
204	    { id: 'markup' as ToolId, icon: '📦', label: 'Material Markup', desc: 'Never undersell materials again' },
205	    { id: 'timeestimate' as ToolId, icon: '⏱', label: 'Time Estimator', desc: 'How long will it actually take?' },
206	    { id: 'fuelcost' as ToolId, icon: '⛽', label: 'Fuel Cost Calc', desc: 'Know your true travel cost' },
207	    { id: 'invoice' as ToolId, icon: '🧾', label: 'Invoice Generator', desc: 'Instant professional invoice' },
208	    { id: 'profit' as ToolId, icon: '📈', label: 'Profit Margin', desc: 'Is this job actually profitable?' },
209	    { id: 'cashflow' as ToolId, icon: '💰', label: 'Cash Flow Forecast', desc: 'Predict your money 12 months out' },
210	    { id: 'vatcheck' as ToolId, icon: '🔍', label: 'VAT Threshold Checker', desc: 'Are you close to the VAT limit?' },
211	  ];
212	
213	  return (
214	    <div className="min-h-screen bg-deep-slate text-slate-100 font-sans selection:bg-high-vis-orange selection:text-deep-slate">
215	
216	      {/* ── NAV ── */}
217	      <nav className="fixed top-0 w-full z-50 px-4 py-4 sm:px-6">
218	        <div className="max-w-7xl mx-auto">
219	          <div className="bg-deep-slate/80 backdrop-blur-xl border border-white/10 rounded-sm px-6 py-3 flex justify-between items-center shadow-2xl">
220	            <div className="flex items-center gap-4">
221	              <div className="group flex items-center gap-3 cursor-pointer">
222	                <div className="w-10 h-10 bg-high-vis-orange rounded-sm flex items-center justify-center font-display text-2xl font-extrabold text-deep-slate italic group-hover:bg-white transition-colors">JF</div>
223	                <div className="flex flex-col">
224	                  <span className="font-display text-2xl font-extrabold uppercase tracking-tighter italic leading-none">JobFilter</span>
225	                  <span className="text-[8px] font-extrabold uppercase tracking-[0.3em] text-high-vis-orange leading-none mt-1">Built For Trades</span>
226	                </div>
227	              </div>
228	            </div>
229	            <div className="hidden lg:flex items-center gap-10">
230	              <div className="flex items-center gap-8 text-[10px] font-extrabold uppercase tracking-[0.2em] text-slate-400">
231	                <a href="#filter" className="hover:text-electric-cyan transition-colors">Find Jobs Near You</a>
232	                <a href="#tools" className="hover:text-electric-cyan transition-colors">Free Tools</a>
233	                <a href="#roi" className="hover:text-electric-cyan transition-colors">ROI Calc</a>
234	                <a href="#pricing" className="hover:text-electric-cyan transition-colors">Pricing</a>
235	              </div>
236	              <div className="h-4 w-px bg-white/10"></div>
237	              <div className="flex items-center gap-4">
238	                <a href="/login" className="text-[10px] font-extrabold uppercase tracking-widest text-slate-400 hover:text-white transition-colors">Log In</a>
239	                <a href="#filter" onClick={() => trackEvent('nav_cta_click')} className="bg-high-vis-orange text-deep-slate text-[10px] font-extrabold px-4 py-2 rounded-sm uppercase tracking-widest hover:bg-amber-500 transition-all glow-orange">
240	                  Find Jobs Near Me
241	                </a>
242	              </div>
243	            </div>
244	            <div className="flex items-center gap-6">
245	              <div className="hidden sm:flex flex-col items-end">
246	                <div className="flex items-center gap-2">
247	                  <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse shadow-[0_0_8px_#22c55e]"></span>
248	                  <span className="text-[9px] font-extrabold uppercase tracking-tighter text-green-500">LIVE</span>
249	                </div>
250	              </div>
251	              <button className="lg:hidden text-slate-400 hover:text-white transition-colors" onClick={() => setMobileMenuOpen(o => !o)} aria-label="Toggle menu">
252	                {mobileMenuOpen
253	                  ? <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
254	                  : <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7"/></svg>
255	                }
256	              </button>
257	            </div>
258	          </div>
259	          {mobileMenuOpen && (
260	            <div className="lg:hidden mt-2 bg-deep-slate/95 backdrop-blur-xl border border-white/10 rounded-sm px-6 py-4 flex flex-col gap-4">
261	              <a href="#filter" onClick={() => setMobileMenuOpen(false)} className="text-[11px] font-extrabold uppercase tracking-widest text-slate-300 hover:text-electric-cyan transition-colors">Find Jobs Near You</a>
262	              <a href="#tools" onClick={() => setMobileMenuOpen(false)} className="text-[11px] font-extrabold uppercase tracking-widest text-slate-300 hover:text-electric-cyan transition-colors">Free Tools</a>
263	              <a href="#roi" onClick={() => setMobileMenuOpen(false)} className="text-[11px] font-extrabold uppercase tracking-widest text-slate-300 hover:text-electric-cyan transition-colors">ROI Calc</a>
264	              <a href="#pricing" onClick={() => setMobileMenuOpen(false)} className="text-[11px] font-extrabold uppercase tracking-widest text-slate-300 hover:text-electric-cyan transition-colors">Pricing</a>
265	              <a href="#filter" onClick={() => setMobileMenuOpen(false)} className="mt-2 text-center bg-high-vis-orange text-deep-slate text-[11px] font-extrabold py-3 rounded-sm uppercase tracking-widest">Find Jobs Near Me</a>
266	            </div>
267	          )}
268	        </div>
269	      </nav>
270	
271	      {/* ── HERO ── */}
272	      <header className="relative pt-40 pb-28 px-6 overflow-hidden">
273	        <div className="max-w-5xl mx-auto text-center relative z-10">
274	          <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="inline-flex items-center gap-2 bg-amber-500/10 border border-amber-500/30 rounded-sm px-4 py-2 mb-8">
275	            <span className="w-1.5 h-1.5 bg-high-vis-orange rounded-full animate-pulse"></span>
276	            <span className="text-[10px] font-extrabold uppercase tracking-widest text-high-vis-orange">Free — No Card Needed</span>
277	          </motion.div>
278	
279	          <motion.h1
280	            initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
281	            className="font-display text-6xl md:text-9xl font-extrabold tracking-tighter mb-6 leading-[0.85] uppercase italic"
282	          >
283	            Stop Wasting Time<br /><span className="text-high-vis-orange">On Bad Jobs.</span>
284	          </motion.h1>
285	
286	          <motion.p
287	            initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.15 }}
288	            className="text-lg md:text-2xl text-slate-400 max-w-2xl mx-auto mb-4 leading-snug font-medium"
289	          >
290	            Enter your postcode. JobFilter scans local leads, kills the rubbish, and shows you only the jobs worth quoting. Free forever.
291	          </motion.p>
292	
293	          <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.3 }} className="text-sm text-slate-500 font-bold uppercase tracking-widest mb-10">
294	            Electricians · Plumbers · Builders · Heating Engineers · General Trade
295	          </motion.p>
296	
297	          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: 0.35 }} className="flex flex-col sm:flex-row gap-4 justify-center">
298	            <a href="#filter" onClick={() => trackEvent('hero_cta_click', { source: 'hero' })}
299	              className="inline-flex items-center justify-center gap-3 bg-high-vis-orange hover:bg-amber-500 text-deep-slate text-xl font-extrabold py-5 px-10 rounded-sm shadow-2xl glow-orange transition-all transform hover:scale-105 active:scale-95 uppercase italic">
300	              Find Jobs Near Me →
301	            </a>
302	            <a href="#tools" className="inline-flex items-center justify-center gap-3 bg-white/5 hover:bg-white/10 border border-white/10 text-white text-xl font-extrabold py-5 px-10 rounded-sm transition-all uppercase italic">
303	              Free Trade Tools
304	            </a>
305	          </motion.div>
306	
307	          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.5 }} className="mt-10 flex flex-wrap justify-center gap-8 text-xs font-bold uppercase tracking-widest text-slate-500">
308	            <span>✓ No account needed</span>
309	            <span>✓ 3 full records free / month</span>
310	            <span>✓ Postcode-accurate filtering</span>
311	            <span>✓ 10 free trade tools</span>
312	          </motion.div>
313	        </div>
314	
315	        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-full opacity-15 pointer-events-none">
316	          <div className="absolute top-[-10%] left-[-10%] w-[60%] h-[60%] bg-amber-500 rounded-full blur-[180px]"></div>
317	          <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-cyan-500 rounded-full blur-[180px]"></div>
318	        </div>
319	      </header>
320	
321	      {/* ── SOCIAL PROOF STRIP ── */}
322	      <div className="py-6 px-6 bg-charcoal/50 border-y border-white/5">
323	        <div className="max-w-5xl mx-auto flex flex-wrap justify-center gap-10 text-center">
324	          {[
325	            { v: '2,400+', l: 'Leads Scanned' },
326	            { v: '£340', l: 'Avg Saved / Month' },
327	            { v: '94%', l: 'Bad Leads Filtered' },
328	            { v: '10', l: 'Free Trade Tools' },
329	          ].map(({ v, l }) => (
330	            <div key={l}>
331	              <p className="font-display text-3xl font-extrabold text-high-vis-orange italic">{v}</p>
332	              <p className="text-[10px] font-extrabold uppercase tracking-widest text-slate-500 mt-1">{l}</p>
333	            </div>
334	          ))}
335	        </div>
336	      </div>
337	
338	      {/* ── THE FILTER ── */}
339	      <section id="filter" className="py-24 px-6 bg-charcoal/30 border-y border-white/5">
340	        <div className="max-w-4xl mx-auto">
341	          <div className="text-center mb-12">
342	            <h2 className="font-display text-4xl md:text-6xl font-extrabold uppercase italic mb-3">THE <span className="text-electric-cyan">FILTER</span></h2>
343	            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Enter postcode → see only the jobs worth your time</p>
344	          </div>
345	
346	          <div className="bg-deep-slate p-6 md:p-8 rounded-sm border border-white/10 shadow-2xl">
347	            <div className="grid md:grid-cols-[1.4fr_2fr_1fr] gap-4 mb-6">
348	              <div>
349	                <label className="text-xs font-extrabold text-slate-500 uppercase tracking-widest block mb-2">Your Trade</label>
350	                <select value={tradeType} onChange={(e) => setTradeType(e.target.value)}
351	                  className="w-full bg-slate-900/70 border border-white/10 rounded-sm px-4 py-3 text-sm font-bold uppercase tracking-wide text-slate-100 focus:outline-none focus:border-electric-cyan">
352	                  <option value="general">General Trade</option>
353	                  <option value="electrical">Electrical</option>
354	                  <option value="plumbing">Plumbing</option>
355	                  <option value="heating">Heating</option>
356	                  <option value="building">Building</option>
357	                </select>
358	              </div>
359	              <div>
360	                <label className="text-xs font-extrabold text-slate-500 uppercase tracking-widest block mb-2">Your Postcode</label>
361	                <input value={postcode} onChange={(e) => setPostcode(e.target.value.toUpperCase())} placeholder="e.g. B14 7QH"
362	                  className="w-full bg-slate-900/70 border border-white/10 rounded-sm px-4 py-3 text-xl font-bold uppercase tracking-wide text-slate-100 placeholder:text-slate-600 focus:outline-none focus:border-electric-cyan" />
363	              </div>
364	              <div className="flex items-end">
365	                <button onClick={startScan} disabled={isScanning || postcode.trim().length < 4}
366	                  className="w-full bg-high-vis-orange disabled:bg-slate-700 disabled:text-slate-500 hover:bg-amber-500 text-deep-slate font-extrabold py-3 px-4 rounded-sm uppercase italic tracking-widest transition-all h-[52px] text-sm">
367	                  {isScanning ? 'Scanning...' : 'Scan Jobs'}
368	                </button>
369	              </div>
370	            </div>
