        continue;
      }
      return r;
    } catch (e) {
      if (i === attempts - 1) throw e;
      await new Promise(res => setTimeout(res, 500 * (i + 1)));
    }
  }
  throw new Error('fetch failed after retries');
}

// ── Contracts Finder adapter ───────────────────────────────────────────────────

async function fetchContractsFinder(trade: string): Promise<{ leads: RawLead[]; stats: Partial<SourceStats> }> {
  const keyword = CF_KEYWORDS[trade] ?? CF_KEYWORDS.all;
  const params = new URLSearchParams({
    NoticeType: '0',
    Keyword: keyword,
    Page: '1',
    PageSize: '20',
    SortBy: '0',
  });

  try {
    const r = await fetchWithRetry(`${CF_SEARCH_URL}?${params}`, {
      headers: { Accept: 'application/json', 'User-Agent': 'JobFilter/2.0 (jobfilter.uk)' },
    });

    if (!r.ok) {
      return { leads: [], stats: { failed: true, error: `CF HTTP ${r.status}` } };
    }

    const data = await r.json() as any;
    const notices: any[] = data?.results ?? data?.Results ?? data?.notices ?? [];

    const leads: RawLead[] = notices.map((n: any, i: number) => ({
      rawId: String(n.id ?? n.Id ?? n.noticeId ?? `cf-${Date.now()}-${i}`),
      rawTitle: String(n.title ?? n.Title ?? n.noticeName ?? '').trim(),
      rawDescription: String(n.description ?? n.Description ?? n.noticeDescription ?? '').trim(),
      rawValue: Number(n.estimatedValue ?? n.EstimatedValue ?? n.value ?? n.valueLow ?? 0) || undefined,
      rawValueMin: Number(n.valueLow ?? n.ValueLow ?? 0) || undefined,
      rawValueMax: Number(n.valueHigh ?? n.ValueHigh ?? 0) || undefined,
      rawLocation: String(n.deliveryLocation ?? n.location ?? n.organisationAddress?.town ?? '').trim(),
      rawPostcode: String(n.postcode ?? n.Postcode ?? n.organisationAddress?.postcode ?? '').trim(),
      rawDeadline: String(n.submissionDeadline ?? n.deadlineDate ?? n.closingDate ?? '').trim(),
      rawPublished: String(n.publishedDate ?? n.PublishedDate ?? '').trim(),
      rawBuyer: String(n.buyingOrganisationName ?? n.organisationName ?? n.OrganisationName ?? '').trim(),
      rawCpvCodes: Array.isArray(n.cpvCodes) ? n.cpvCodes.map(String) : [],
      sourceSystem: 'ContractsFinder',
      sourceUrl: n.id ? `https://www.contractsfinder.service.gov.uk/Notice/${n.id}` : undefined,
    })).filter(l => l.rawTitle.length > 3);

    return { leads, stats: { fetched: leads.length, failed: false } };
  } catch (err: any) {
    return { leads: [], stats: { failed: true, error: String(err?.message ?? err) } };
  }
}

// ── FTS adapter (OCDS format) ──────────────────────────────────────────────────

async function fetchFTS(trade: string): Promise<{ leads: RawLead[]; stats: Partial<SourceStats> }> {
  const cpvPrefixes = FTS_CPV[trade] ?? FTS_CPV.all;
  const since = new Date(Date.now() - CONFIG.lookbackDays * 86_400_000).toISOString().split('T')[0];

  // Try each CPV prefix, collect up to 20 results total
  const allLeads: RawLead[] = [];

  for (const cpvPrefix of cpvPrefixes.slice(0, 3)) {
    if (allLeads.length >= 20) break;
    const params = new URLSearchParams({
      updatedFrom: since,
      pageSize: '15',
      page: '0',
    });

    const urls = [
      `${FTS_BASE}?${params}&CPVCodes=${cpvPrefix}`,
      `${FTS_BASE}?${params}`,
    ];

    for (const url of urls) {
      try {
        const r = await fetchWithRetry(url, {
          headers: { Accept: 'application/json', 'User-Agent': 'JobFilter/2.0' },
        });
        if (!r.ok) continue;

        const pkg = await r.json() as any;
        const releases: any[] = pkg?.releases ?? pkg?.data?.releases ?? [];

        for (const rel of releases) {
          if (allLeads.length >= 20) break;
          const tender = rel?.tender ?? {};
          const buyer = rel?.buyer ?? rel?.parties?.find((p: any) => p.roles?.includes('buyer')) ?? {};
          const items: any[] = tender?.items ?? [];
          const cpvCodes = items.flatMap((it: any) => [
            it?.classification?.id,
            ...(it?.additionalClassifications ?? []).map((c: any) => c?.id),
          ]).filter(Boolean).map(String);

          const deliveryLocs: any[] = tender?.deliveryLocations ?? [];
          const locationText = deliveryLocs.map((l: any) => l?.description ?? l?.region ?? '').filter(Boolean).join(', ')
            || tender?.deliveryAddress?.region
            || '';

          allLeads.push({
            rawId: String(rel?.ocid ?? rel?.id ?? `fts-${Date.now()}-${allLeads.length}`),
            rawTitle: String(tender?.title ?? '').trim(),
            rawDescription: String(tender?.description ?? '').trim(),
            rawValue: Number(tender?.value?.amount ?? 0) || undefined,
            rawLocation: locationText,
            rawPostcode: '',
            rawDeadline: String(tender?.tenderPeriod?.endDate ?? tender?.contractPeriod?.endDate ?? '').trim(),
            rawPublished: String(rel?.date ?? '').trim(),
            rawBuyer: String(buyer?.name ?? tender?.procuringEntity?.name ?? '').trim(),
            rawCpvCodes: cpvCodes,
            sourceSystem: 'FTS',
            sourceUrl: rel?.ocid
              ? `https://www.find-tender.service.gov.uk/Notice/${rel.ocid.split('-').pop()}`
              : undefined,
          });
        }
        break; // success with this URL, no need to try fallback
      } catch {
        continue;
      }
    }
  }

  return {
    leads: allLeads.filter(l => l.rawTitle.length > 3),
    stats: { fetched: allLeads.length, failed: false },
  };
}

// ── Public entry point ─────────────────────────────────────────────────────────

export async function contractsFetcher(trade: string): Promise<{ leads: RawLead[]; stats: Record<string, SourceStats> }> {
  const [cfResult, ftsResult] = await Promise.allSettled([
    fetchContractsFinder(trade),
    fetchFTS(trade),
  ]);

  const cf = cfResult.status === 'fulfilled' ? cfResult.value : { leads: [], stats: { failed: true, error: 'ContractsFinder threw' } };
  const fts = ftsResult.status === 'fulfilled' ? ftsResult.value : { leads: [], stats: { failed: true, error: 'FTS threw' } };

  const cfStats: SourceStats = { fetched: cf.leads.length, passed: 0, dropped: 0, failed: cf.stats.failed ?? false, error: cf.stats.error };
  const ftsStats: SourceStats = { fetched: fts.leads.length, passed: 0, dropped: 0, failed: fts.stats.failed ?? false, error: fts.stats.error };

  return {
    leads: [...cf.leads, ...fts.leads],
    stats: { ContractsFinder: cfStats, FTS: ftsStats },
  };
}

