import type { RawLead, SourceStats } from '../types.ts';
import { CONFIG } from '../config.ts';

// ── Planning Data Fetcher ──────────────────────────────────────────────────────
// Source: planning.data.gov.uk public API (free, no auth)
// Purpose: new planning applications = intent signal for future trade work
//          (new builds, extensions, conversions → demand for plumbers, electricians, builders etc.)

const PLANNING_BASE = 'https://www.planning.data.gov.uk/api/v1/search.json';

// Trade → planning application types that signal demand for that trade
const PLANNING_KEYWORDS: Record<string, string[]> = {
  plumbing:    ['house', 'extension', 'conversion', 'bathroom', 'kitchen', 'dwelling'],
  electrical:  ['house', 'extension', 'solar', 'ev', 'dwelling', 'commercial'],
  roofing:     ['roof', 'extension', 'dormer', 'loft', 'reroofing', 'house'],
  building:    ['extension', 'conversion', 'new build', 'house', 'development'],
  carpentry:   ['extension', 'house', 'conversion', 'dwelling'],
  painting:    ['house', 'external', 'commercial', 'residential'],
  hvac:        ['commercial', 'office', 'house', 'extension', 'air'],
  landscaping: ['garden', 'landscaping', 'grounds', 'commercial', 'park'],
  all:         ['house', 'extension', 'development', 'commercial', 'conversion'],
};

async function fetchPlanningApplications(
  outward: string,
  region: string,
  trade: string
): Promise<{ leads: RawLead[]; stats: Partial<SourceStats> }> {
  const keywords = PLANNING_KEYWORDS[trade] ?? PLANNING_KEYWORDS.all;

  // Try the planning data API
  const params = new URLSearchParams({
    dataset: 'development-plan-document',
    limit: '20',
    offset: '0',
    // Use geometry lookup based on region if possible
  });

  // Primary attempt: query by local-authority-district or region
  const urls = [
    `${PLANNING_BASE}?dataset=planning-permission&limit=20&organisation_entity=${encodeURIComponent(region)}`,
    `https://www.planning.data.gov.uk/api/v1/search.json?q=${encodeURIComponent(keywords[0])}&dataset=planning-permission&limit=20`,
    `https://www.planning.data.gov.uk/api/v1/entities.json?dataset=planning-permission&limit=15`,
  ];

  for (const url of urls) {
    try {
      const r = await fetch(url, {
        headers: { Accept: 'application/json', 'User-Agent': 'JobFilter/2.0' },
        signal: AbortSignal.timeout(CONFIG.fetchTimeoutMs),
      });
      if (!r.ok) continue;

      const data = await r.json() as any;
      const entities: any[] = data?.entities ?? data?.results ?? data?.data ?? [];
      if (!entities.length) continue;

      const leads: RawLead[] = entities
        .filter((e: any) => {
          const desc = String(e?.description ?? e?.name ?? e?.reference ?? '').toLowerCase();
          return keywords.some(k => desc.includes(k)) || desc.includes('house') || desc.includes('build');
        })
        .slice(0, 10)
        .map((e: any, i: number) => ({
          rawId: String(e?.entity ?? e?.reference ?? e?.id ?? `planning-${Date.now()}-${i}`),
          rawTitle: `Planning Approval: ${String(e?.name ?? e?.description ?? 'New Development').substring(0, 80)}`,
          rawDescription: `Recently approved planning application in ${outward} area — potential ${trade} work opportunity. Reference: ${e?.reference ?? 'N/A'}`,
          rawValue: estimateValueFromPlanningType(String(e?.description ?? e?.name ?? ''), trade),
          rawLocation: String(e?.address ?? e?.locality ?? e?.organisation ?? outward),
          rawPostcode: outward,
          rawDeadline: '',
          rawPublished: String(e?.entry_date ?? e?.start_date ?? new Date().toISOString()),
          rawBuyer: String(e?.organisation ?? e?.['organisation-entity'] ?? 'Local Authority'),
          rawCpvCodes: [],
          sourceSystem: 'PlanningData',
          sourceUrl: e?.entity ? `https://www.planning.data.gov.uk/entity/${e.entity}` : undefined,
        }));

      return { leads, stats: { fetched: leads.length, failed: false } };
    } catch {
      continue;
    }
  }

  return { leads: [], stats: { fetched: 0, failed: true, error: 'Planning API unavailable' } };
}

function estimateValueFromPlanningType(description: string, trade: string): number {
  const d = description.toLowerCase();
  // Rough value estimates based on planning description keywords
  if (d.includes('loft') || d.includes('dormer')) return 35_000;
  if (d.includes('extension') && d.includes('storey')) return 40_000;
  if (d.includes('extension')) return 25_000;
  if (d.includes('new') && d.includes('dwell')) return 200_000;
  if (d.includes('conversion')) return 50_000;
  if (d.includes('solar') || d.includes('ev')) return 8_000;
  if (d.includes('commercial')) return 80_000;
  // Fall back by trade
  const defaults: Record<string, number> = {
    plumbing: 3_000, electrical: 4_000, roofing: 10_000,
    building: 30_000, carpentry: 5_000, painting: 4_000,
    hvac: 12_000, landscaping: 8_000, all: 15_000,
  };
  return defaults[trade] ?? 15_000;
}

export async function planningDataFetcher(
  outward: string,
  region: string,
  trade: string
): Promise<{ leads: RawLead[]; stats: Record<string, SourceStats> }> {
  const result = await fetchPlanningApplications(outward, region, trade);
  const stats: SourceStats = {
    fetched: result.leads.length,
    passed: 0,
    dropped: 0,
    failed: result.stats.failed ?? false,
    error: result.stats.error,
  };
  return { leads: result.leads, stats: { PlanningData: stats } };
}

