import type { RawLead, SourceStats } from '../types.ts';
import { CONFIG } from '../config.ts';

// ── CPV prefix → trade mapping (post-fetch filter) ────────────────────────────
const CPV_TRADE_PREFIXES: Record<string, string[]> = {
